/**
 * Merges expansion birds into the main species array.
 * Call this after importing SPECIES from species.js
 * @param {Array} speciesList - The base species array
 * @returns {Array} Combined species array with expansion birds appended
 */
export function loadBirdExpansion(speciesList) {
  const existingIds = new Set(speciesList.map(s => s.id));
  const newBirds = EXPANSION_BIRDS.filter(b => !existingIds.has(b.id));
  return [...speciesList, ...newBirds];
}

export default EXPANSION_BIRDS;
